```jsx
import React, { useState, useMemo } from 'react';
import './WarrantyClaimsTable.css'; // Assuming CSS is in a separate file

// --- Mock Data ---
// In a real app, this would likely come from an API fetch.
const MOCK_DATA = [
  { id: 101, customer: 'Alice Smith', product: 'Model X Laptop', date: '2023-10-25', status: 'Pending', amount: 150.00 },
  { id: 102, customer: 'Bob Johnson', product: '4K Monitor', date: '2023-11-01', status: 'Approved', amount: 450.50 },
  { id: 103, customer: 'Charlie Brown', product: 'Wireless Headphones', date: '2023-11-15', status: 'Rejected', amount: 80.00 },
  { id: 104, customer: 'Diana Prince', product: 'Smart Watch', date: '2023-12-05', status: 'Approved', amount: 220.00 },
  { id: 105, customer: 'Ethan Hunt', product: 'Model X Laptop', date: '2024-01-10', status: 'Pending', amount: 150.00 },
  { id: 106, customer: 'Fiona Gallagher', product: 'Tablet Pro', date: '2024-01-12', status: 'Approved', amount: 600.00 },
  { id: 107, customer: 'George Martin', product: 'Gaming Mouse', date: '2024-01-20', status: 'Rejected', amount: 45.99 },
  { id: 108, customer: 'Hannah Abbott', product: '4K Monitor', date: '2024-02-01', status: 'Pending', amount: 450.50 },
];

const WarrantyClaimsTable = () => {
  // --- State ---
  const [data] = useState(MOCK_DATA);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });

  // --- Handlers ---
  const handleFilterTextChange = (e) => setFilterText(e.target.value);
  const handleStatusFilterChange = (e) => setStatusFilter(e.target.value);

  const requestSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  // --- Data Processing (Filtering & Sorting) ---
  // useMemo ensures this expensive calculation only runs when dependencies change.
  const processedData = useMemo(() => {
    let actionableData = [...data];

    // 1. Apply Filtering
    if (statusFilter !== 'All') {
      actionableData = actionableData.filter(item => item.status === statusFilter);
    }

    if (filterText) {
      const lowerText = filterText.toLowerCase();
      actionableData = actionableData.filter(item =>
        item.customer.toLowerCase().includes(lowerText) ||
        item.product.toLowerCase().includes(lowerText) ||
        item.id.toString().includes(lowerText)
      );
    }

    // 2. Apply Sorting
    if (sortConfig.key) {
      actionableData.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];

        if (valA < valB) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (valA > valB) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
      });
    }

    return actionableData;
  }, [data, filterText, statusFilter, sortConfig]);


  // Helper to render sort arrow
  const getClassNamesFor = (name) => {
    if (!sortConfig.key) return;
    return sortConfig.key === name ? sortConfig.direction : undefined;
  };

  return (
    <div className="claims-container">
      <h2>Warranty Claims Dashboard</h2>

      {/* --- Controls Area --- */}
      <div className="controls">
        <div className="control-group">
          <label htmlFor="search">Search:</label>
          <input
            id="search"
            type="text"
            placeholder="Customer, Product, or ID..."
            value={filterText}
            onChange={handleFilterTextChange}
          />
        </div>
        <div className="control-group">
          <label htmlFor="status">Status:</label>
          <select id="status" value={statusFilter} onChange={handleStatusFilterChange}>
            <option value="All">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="Approved">Approved</option>
            <option value="Rejected">Rejected</option>
          </select>
        </div>
      </div>

      {/* --- Table Area --- */}
      <table className="claims-table">
        <thead>
          <tr>
            {/* Clickable headers for sorting */}
            <th onClick={() => requestSort('id')} className={getClassNamesFor('id')}>
              Claim ID {sortConfig.key === 'id' ? (sortConfig.direction === 'asc' ? '▲' : '▼') : ''}
            </th>
            <th onClick={() => requestSort('customer')} className={getClassNamesFor('customer')}>
              Customer {sortConfig.key === 'customer' ? (sortConfig.direction === 'asc' ? '▲' : '▼') : ''}
            </th>
            <th onClick={() => requestSort('product')} className={getClassNamesFor('product')}>
              Product {sortConfig.key === 'product' ? (sortConfig.direction === 'asc' ? '▲' : '▼') : ''}
            </th>
            <th onClick={() => requestSort('date')} className={getClassNamesFor('date')}>
              Date Submitted {sortConfig.key === 'date' ? (sortConfig.direction === 'asc' ? '▲' : '▼') : ''}
            </th>
            <th onClick={() => requestSort('status')} className={getClassNamesFor('status')}>
              Status {sortConfig.key === 'status' ? (sortConfig.direction === 'asc' ? '▲' : '▼') : ''}
            </th>
            <th onClick={() => requestSort('amount')} className={getClassNamesFor('amount')}>
              Amount {sortConfig.key === 'amount' ? (sortConfig.direction === 'asc' ? '▲' : '▼') : ''}
            </th>
          </tr>
        </thead>
        <tbody>
          {processedData.length > 0 ? (
            processedData.map((claim) => (
              <tr key={claim.id}>
                <td>#{claim.id}</td>
                <td>{claim.customer}</td>
                <td>{claim.product}</td>
                <td>{new Date(claim.date).toLocaleDateString()}</td>
                <td>
                  <span className={`status-badge status-${claim.status.toLowerCase()}`}>
                    {claim.status}
                  </span>
                </td>
                <td>${claim.amount.toFixed(2)}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="6" style={{ textAlign: 'center' }}>No matching records found.</td>
            </tr>
          )}
        </tbody>
      </table>
      <div className="footerInfo">
          Showing {processedData.length} of {data.length} records.
      </div>
    </div>
  );
};

export default WarrantyClaimsTable;
```

